noncompliant:
// Noncompliant: HttpOnly not set
var cookie = new HttpCookie("SessionId", sessionId);
Response.Cookies.Add(cookie);

// Noncompliant: Explicitly set to false
var cookie = new HttpCookie("SessionId", sessionId)
{
    HttpOnly = false
};
Response.Cookies.Add(cookie);

compliant:
// Compliant: HttpOnly flag set to true
var cookie = new HttpCookie("SessionId", sessionId)
{
    HttpOnly = true
};
Response.Cookies.Add(cookie);

// Compliant: ASP.NET Core with HttpOnly
Response.Cookies.Append("SessionId", sessionId, new CookieOptions
{
    HttpOnly = true,
    Secure = true
});
